// // This module compares two 4-bit numbers and outputs whether the first number is less than or equal to the second number.
module comparator_4bit(
    input wire [3:0] a,
    input wire [3:0] b,
    output wire gt,
    output wire lt,
    output wire eq
);

    assign gt = (a > b);
    assign lt = (a < b);
    assign eq = (a == b);

endmodule
